"use strict";var maxLatitude=85.0511287798,r=63.78137,deg2rad=Math.PI/180,WebMercator=function(){function t(){this.bounds={x1:-200.37508342789243,x2:200.37508342789243,y1:-200.3750834278071,y2:200.3750834278071},this.maxLatitude=maxLatitude}return t.prototype.forward=function(t){var a=Math.sin(t[1]*deg2rad),a=[r*t[0]*deg2rad,r*Math.log((1+a)/(1-a))/2];return Math.abs(t[1])>maxLatitude&&(a.outside=!0),a},t.prototype.inverse=function(t){return[t[0]/(r*deg2rad),(2*Math.atan(Math.exp(t[1]/r))-Math.PI/2)/deg2rad]},t}();export default WebMercator;